#include<bits/stdc++.h>
using namespace std;
struct edge
{
    int to,val,nxt;
}e[200010];
int head[200010],tot=1;
int n,m,s,t,d[200010],now[200010];
char a[5050][5050];
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};
void add1(int u,int v,int w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(int u,int v,int w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(int i=0;i<=t;i++)
    {
        d[i]=0;
    }
    d[s]=1;
    queue<int> q;
    q.push(s);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
int flag[200010],flag1[200010];
int dfs(int x,int flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    int sum=0;
    for(int i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        int v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            int tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
int dinic()
{
    int ans=0;
    while(bfs())
    {
        for(int i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,2e9);
    }
    return ans;
}
bool vis[200010];
int flag2;
void dfs1(int x,int v)
{
    if(vis[x])
    {
        return;
    }
    vis[x]=true;
    if(flag[x]==v)
    {
        flag1[x]=1;
        flag2=1;
    }
    for(int i=head[x];i;i=e[i].nxt)
    {
        int to=e[i].to,val=e[i].val;
        if(val==v)
        {
            dfs1(to,v);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%s",a[i]+1);
    }
    s=0;
    t=n*m+1;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            int now=(i-1)*m+j;
            if((i+j)%2==1&&a[i][j]!='#')
            {
                flag[now]=1;
                add(s,now,1);
                for(int k=0;k<=3;k++)
                {
                    int p=i+dx[k],q=j+dy[k];
                    if(p>0&&p<=n&&q>0&&q<=m&&a[p][q]!='#')
                    {
                        add(now,(p-1)*m+q,1);
                    }
                }
            }
            else if((i+j)%2==0&&a[i][j]!='#')
            {
                add(now,t,1);
            }
        }
    }
    dinic();
    dfs1(s,1);
    memset(vis,0,sizeof(vis));
    dfs1(t,0);
    if(flag2)
    {
        printf("WIN\n");
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=m;j++)
            {
                if(flag1[(i-1)*m+j])
                {
                    printf("%d %d\n",i,j);
                }
            }
        }
    }
    else
    {
        printf("LOSE");
    }
    return 0;
}
